#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

// Function to generate a random session token
char* generate_token() {
  // Get the current time in seconds since epoch
  time_t current_time = time(NULL);

  // Generate a random number between 0 and 10000
  int random_number = rand() % 10000;

  // Create a buffer to store the token
  char token[17];

  // Convert the current time to a string using sprintf
  sprintf(token, "%ld", current_time);

  // Append the random number to the token
  strcat(token, random_number);

  return token;
}